sp_widget.client_script:
function widgetController($scope, spUtil) {
  var c = this;

  c.checkIn = function(res) {
    c.server.update({action: 'checkIn', sys_id: res.sys_id}).then(function(r) {
      if (c.data.error) {
        spUtil.addErrorMessage(c.data.error);
      } else {
        spUtil.addTrivialMessage(c.data.success || 'Checked in: ' + res.number);
      }
      c.server.refresh();
    });
  };

  c.checkOut = function(res) {
    c.server.update({action: 'checkOut', sys_id: res.sys_id}).then(function(r) {
      if (c.data.error) {
        spUtil.addErrorMessage(c.data.error);
      } else {
        spUtil.addTrivialMessage(c.data.success || 'Checked out: ' + res.number);
      }
      c.server.refresh();
    });
  };
}

sp_widget.script:
(function() {

  gs.info('WRM Widget - input received: ' + JSON.stringify(input), 'WRMWidget');

  if (input && input.action && input.sys_id) {
    gs.info('WRM Widget - action: ' + input.action + ' sys_id: ' + input.sys_id, 'WRMWidget');

    var helper = new WRMReservationHelper();
    var result;

    if (input.action === 'checkIn') {
      result = helper.checkIn(input.sys_id, gs.getUserID());
    } else if (input.action === 'checkOut') {
      result = helper.checkOut(input.sys_id, gs.getUserID());
    }

    gs.info('WRM Widget - result: ' + JSON.stringify(result), 'WRMWidget');

    if (result) {
      if (result.success) {
        data.success = result.message;
      } else {
        data.error = result.error;
      }
    }
  }

  // Load reservations for current user
  var reservations = [];
  var grList = new GlideRecord('x_451445_wrm_reservation_tracker');
  grList.addQuery('reserved_for', gs.getUserID());
  grList.orderByDesc('start_date_time');
  grList.setLimit(10);
  grList.query();

  while (grList.next()) {
    var status = grList.getValue('reservation_status') + '';
    var isPending   = (status === 'pending_check_in');
    var isCheckedIn = (status === 'checked_in');

    var statusClass = 'label-default';
    if (isPending)              statusClass = 'label-warning';
    if (isCheckedIn)            statusClass = 'label-success';
    if (status === 'cancelled') statusClass = 'label-danger';
    if (status === 'no_show')   statusClass = 'label-danger';

    reservations.push({
      sys_id:             grList.getUniqueValue(),
      number:             grList.getValue('number'),
      workspace:          grList.getDisplayValue('workspace'),
      reservation_status: grList.getDisplayValue('reservation_status'),
      start_date_time:    grList.getDisplayValue('start_date_time'),
      end_date_time:      grList.getDisplayValue('end_date_time'),
      location:           grList.getDisplayValue('location'),
      statusClass:        statusClass,
      canCheckIn:         isPending,
      canCheckOut:        isCheckedIn
    });
  }

  data.reservations = reservations;
  data.error        = data.error || null;
  data.success      = data.success || null;

})();
